INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'ed67aaab-7be1-447b-ba2c-4fc964424ad2',
  '00000000-0000-0000-0000-000000000001',
  $escape$Solana — Understanding Account Model and Sealevel Parallel Execution$escape$,
  $escape$Solana's account model is based on a flat, key-value store where each account has a unique address. Programs and accounts are distinct entities, with programs being stateless and accounts holding the program's state. The Proof of History (PoH) consensus algorithm is used in conjunction with Proof of Stake (PoS) to secure the network. Sealevel parallel execution allows for the parallel processing of transactions, significantly improving the network's throughput. This is achieved through the use of a parallel scheduler that can process multiple transactions simultaneously, while still maintaining the integrity of the blockchain.$escape$,
  NULL,
  NULL,
