INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0860b729-7b4f-49da-b967-91c34958dbee',
  '00000000-0000-0000-0000-000000000001',
  $escape$Solana — Tendermint Consensus: A Primer for Solana Developers$escape$,
  $escape$Tendermint is a Byzantine Fault Tolerant (BFT) consensus algorithm used by Cosmos. Solana's Tendermint Core implementation is based on the Tendermint Core 0.34.13 version. To understand how Tendermint integrates with Solana's architecture, consider the following: Solana's Tendermint Core is responsible for maintaining the state machine, which is stored in a database. The Tendermint Core uses a set of validators to achieve consensus. Solana's Tendermint Core communicates with the Solana Core through the ABCI (Application Blockchain Interface) protocol. The ABCI protocol enables the Solana Core to interact with the Tendermint Core and perform tasks such as creating new blocks.$escape$,
  NULL,
  NULL,
