INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd22c04e9-2948-47a4-b595-017f8151d9ad',
  '00000000-0000-0000-0000-000000000001',
  $escape$Solana Consensus: PoH and BFT Variants$escape$,
  $escape$Solana's consensus mechanism, Proof of History (PoH), replaces Proof of Work (PoW) to achieve faster transaction validation. PoH uses a leader-based protocol, where a leader node is elected to create a new block. Solana's BFT (Byzantine Fault Tolerance) variant, known as Turbine, ensures finality by using a leader-based approach combined with a gossip protocol. This allows Solana to achieve high throughput and low latency. Solana also uses a variant of the BFT algorithm known as PBFT (Practical Byzantine Fault Tolerance).$escape$,
  NULL,
  NULL,
