INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '546afdce-a3bf-476d-aecf-22f762c72ebc',
  '00000000-0000-0000-0000-000000000001',
  $escape$Solana Wallets — Mastering Bitcoin Script for Non-CVM Transactions$escape$,
  $escape$When interacting with Solana wallets, you'll often encounter Bitcoin Script, the stack-based scripting language used for non-CVM (Cross-Chain Validator Model) transactions. Bitcoin Script is intentionally limited, yet powerful, enabling features like P2PKH (Pay-to-Public-Key-Hash) and P2SH (Pay-to-Script-Hash). Solana's wallet library provides a `tx` object, which includes a `getSignatureProgramId` method for generating program IDs specific to the wallet. To create a multisig wallet, you'll need to define a script that requires multiple signatures. For example, you can use the `AND` operator to combine two signatures, like `OP_2 OP_CHECKMULTISIGVERIFY`.$escape$,
  $escape$import { PublicKey, sysvar } from '@solana/web3.js';
const wallet = new Wallet();
const address = wallet.publicKey;
const signatureProgramId = wallet.getSignatureProgramId();
const script = new PublicKey('9a8b7c6d5e4f3g2h1i0').toBuffer();
console.log(script);$escape$,
  $escape$typescript$escape$,
